record_types.code:
type Token (Kind : Token_Kind := Invalid_Token) is record
   case Kind is
      when String_Token =>
         String_Offset, String_Length : Streams.AS.Stream_Element_Offset;
      when Integer_Token =>
         Integer_Value : Types.Integer_Type;
      when Float_Token =>
         Float_Value   : Types.Float_Type;
      when Boolean_Token =>
         Boolean_Value : Boolean;
      when others =>
         null;
   end case;
end record;

